import base64
import pickle

def process_pubsub_messages(messages):
    results = []
    for message in messages:
        # Decode the base64 encoded message data
        decoded_data = base64.b64decode(message['data'])
        
        # Deserialize the Python object using pickle.loads()
        python_object = pickle.loads(decoded_data)
        
        # Process the deserialized Python object (example processing logic)
        processed_result = process_python_object(python_object)
        
        # Append the result to the results list
        results.append(processed_result)
    
    return results

